type UnescapedCookieParamError struct {
	ParamName string
	Err       error
}

func (e *UnescapedCookieParamError) Error() string {
	return fmt.Sprintf("error unescaping cookie parameter '%s'", e.ParamName)
}

func (e *UnescapedCookieParamError) Unwrap() error {
	return e.Err
}

type UnmarshalingParamError struct {
	ParamName string
	Err       error
}

func (e *UnmarshalingParamError) Error() string {
	return fmt.Sprintf("Error unmarshaling parameter %s as JSON: %s", e.ParamName, e.Err.Error())
}

func (e *UnmarshalingParamError) Unwrap() error {
	return e.Err
}

type RequiredParamError struct {
	ParamName string
}

func (e *RequiredParamError) Error() string {
	return fmt.Sprintf("Query argument %s is required, but not found", e.ParamName)
}

type RequiredHeaderError struct {
	ParamName string
	Err       error
}

func (e *RequiredHeaderError) Error() string {
	return fmt.Sprintf("Header parameter %s is required, but not found", e.ParamName)
}

func (e *RequiredHeaderError) Unwrap() error {
	return e.Err
}

type InvalidParamFormatError struct {
	ParamName string
	Err       error
}

func (e *InvalidParamFormatError) Error() string {
	return fmt.Sprintf("Invalid format for parameter %s: %s", e.ParamName, e.Err.Error())
}

func (e *InvalidParamFormatError) Unwrap() error {
	return e.Err
}

type TooManyValuesForParamError struct {
	ParamName string
	Count     int
}

func (e *TooManyValuesForParamError) Error() string {
	return fmt.Sprintf("Expected one value for %s, got %d", e.ParamName, e.Count)
}

// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{})
}

// ServeMux is an abstraction of [http.ServeMux].
type ServeMux interface {
	HandleFunc(pattern string, handler func(http.ResponseWriter, *http.Request))
	http.Handler
}

type StdHTTPServerOptions struct {
	BaseURL          string
	BaseRouter       ServeMux
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, m ServeMux) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseRouter: m,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/healthz", wrapper.GetLiveness)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/readyz", wrapper.GetReadiness)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/v1/events", wrapper.IngestEvent)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/v1/rates", wrapper.ListRates)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/v1/quotas", wrapper.ListQuotas)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/v1/quotas", wrapper.CreateQuota)
	m.HandleFunc(http.MethodDelete+" "+options.BaseURL+"/api/v1/quotas/{id}", wrapper.DeleteQuota)
	m.HandleFunc(http.MethodPut+" "+options.BaseURL+"/api/v1/quotas/{id}", wrapper.UpdateQuota)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/v1/quotas/{tenant_id}", wrapper.GetQuotaStatus)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/v1/wallets", wrapper.CreateWallet)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/v1/wallets/{id}", wrapper.GetWalletStatus)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/v1/wallets/{id}/top-ups", wrapper.TopUpWallet)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/v1/wallets/{id}/adjustments", wrapper.AdjustWallet)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/v1/wallets/{id}/ledger", wrapper.GetWalletLedger)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/v1/reports/costs", wrapper.GetCostReport)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/v1/reports/breakdown", wrapper.GetCostBreakdown)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/v1/reports/summary", wrapper.GetPipelineSummary)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/v1/customers/{customerID}/entitlements/{featureKey}/value", wrapper.GetEntitlementValue)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/v1/reconcile", wrapper.TriggerReconcile)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/v1/debug/config", wrapper.GetDebugConfig)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/debug/dashboard", wrapper.GetDebugDashboard)

	return m
}

